vex = Vex(api_key='your-vex-api-key')

@vex.guardrail(
    verifications=[
        'code_correctness',
        'security_vulnerability_scanning',
        'no_credential_leakage',
        'dependency_safety',
        'license_compliance'
    ],
    risk_profile='medium'
)
async def before_agent_callback(agent: BaseAgent, session, input_data):
    # Vex automatically scans input_data for all verifications
    verdict = await vex.verify(input_data)
    if not verdict.approved:
        return {'blocked': True, 'reason': verdict.issues}
    return {'approved': True, 'session_hash': session.hash()}

